    "-std=c++0x",
    "-Ic:/users/almostautomated/src/RcppMpfr++/mpreal/inst/include",
    "-Ic:/RtoolsLocal/R-2.15.0/include" )

settings$env$PKG_CXXFLAGS="-IC:/Users/almostautomated/R/win-library/2.15/Rcpp/include"

